-- CI E2E 最小测试数据集 (快照自本地开发库, 已脱敏)
--
-- 用途: 在 GitHub Actions frontend-e2e 作业里,让 Playwright 能真登录并打 /my/* API.
-- 前置: schema/complete_schema_v2.sql 已加载 + migrations/V*.sql 按序全部应用.
--
-- 覆盖账户 (全部使用测试占位手机号/姓名):
--   admin     / admin123     (SUPER_ADMIN, 用于 auth-critical / org / place 测试)
--   teacher01 / admin123     (TEACHER + 班主任绑定, 用于 my-dashboard 测试)
--   teacher02 / (不同 hash)  (TEACHER, 仅保留绑定关系用)
--
-- 再生策略: 若需补录新表数据, 请在本地 dev DB 调试通过后用 mysqldump 的 --where
-- 过滤导出对应行, 追加进本文件并清理 PII. 不要放整表 dump.

SET FOREIGN_KEY_CHECKS = 0;
SET UNIQUE_CHECKS = 0;
SET @OLD_SQL_MODE=@@SQL_MODE;
SET SQL_MODE='NO_AUTO_VALUE_ON_ZERO';










SET SQL_MODE=@OLD_SQL_MODE;
SET FOREIGN_KEY_CHECKS = 1;
SET UNIQUE_CHECKS = 1;
